+                                @MappableIface.RW F32Array tex,int tw, int th
+    ) {
+        int width = (int) uniforms.iResolution().x();
+        int height = (int) uniforms.iResolution().y();
+        var fragColor = mainImage(uniforms, vec4.vec4(0f),
+                vec2.vec2((float)(kc.gix % width),
